const fs = require('fs');
const path = '/Users/orion/.llmwork/chats/1782495335715';
console.log('目录是否存在:', fs.existsSync(path));
if (fs.existsSync(path)) {
  const files = fs.readdirSync(path);
  console.log('文件列表:', files);
  files.forEach(f => {
    const stat = fs.statSync(path + '/' + f);
    console.log(`  ${f} (${stat.size} bytes, ${stat.isDirectory() ? '目录' : '文件'})`);
  });
}
